userDefinedLinkHintCss:
/* Arc Dark theme */

div > .vimiumHintMarker {
  /* Link hint boxes */
  background: #182C61;
  font-size: 13px;
  border: 0.25em solid #383c4a;
  border-radius: 0.68em;
  box-shadow: 0em 0.1em 0.1em 0.1em rgba(24, 44, 97, 0.4);
}

div > .vimiumHintMarker span {
  /* Link hint text */
  color: #e2e3e7;
  font-size: inherit;
  text-shadow: none;
}

div > .vimiumHintMarker > .matchingCharacter {
  /* Link hint matching characters */
  color: #5294e2;
}
